package com.demo.web.dto.Autographs;

public class AutographUpdateRequest { private Integer userId; private String autographIdStr; private String title; private String description; private String newPicUrl; private boolean FileUploaded; public AutographUpdateRequest(Integer userId, String autographIdStr, String title, String description, String newPicUrl, boolean fileUploaded) { this.userId = userId; this.autographIdStr = autographIdStr; this.title = title; this.description = description; this.newPicUrl = newPicUrl; this.FileUploaded = fileUploaded; } public Integer getUserId() { return userId; } public String getAutographIdStr() { return autographIdStr; } public String getTitle() { return title; } public String getDescription() { return description; } public String getNewPicUrl() { return newPicUrl; } public boolean isFileUploaded() { return FileUploaded; } }
